/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[DataEventHandler(tableStr(FreeTextInvoiceHeaderFooterTmp), DataEventType::Inserting)]
public static void FreeTextInvoiceHeaderFooterTmp_onInserting(Common sender, DataEventArgs e)
{
    FreeTextInvoiceHeaderFooterTmp freeTextInvoiceHeaderFooterTmp = sender as FreeTextInvoiceHeaderFooterTmp;

    BankAccountTable bankAccountTable;

    CompanyInfo companyInfo = CompanyInfo::find();

    select * from bankAccountTable where bankAccountTable.AccountID == companyInfo.Bank;

    freeTextInvoiceHeaderFooterTmp.ETGCompanyBankName = bankAccountTable.Name;
    freeTextInvoiceHeaderFooterTmp.ETGBankAccountNum = bankAccountTable.AccountNum;
    freeTextInvoiceHeaderFooterTmp.ETGSWIFTNo = bankAccountTable.SWIFTNo;
}
